const rawData = $input.first().json;

if (!rawData || rawData.error || typeof rawData.disk_pct === 'undefined') {
  const ts = new Date().toLocaleString('en-IL', {timeZone: 'Asia/Jerusalem', hour12: false});
  return [{json: {status: 'RED', message: '\u{1F534} *Server CRITICAL* \u2014 ' + ts + '\n\u26a0\ufe0f skill-api not responding \u2014 system metrics unavailable.\n_Morning skills will likely fail._'}}];
}

const d = rawData;
const issues = [];
let status = 'GREEN';

function flag(cond, msg, sev) {
  if (cond) {
    issues.push(msg);
    if (sev === 'RED') status = 'RED';
    else if (sev === 'YELLOW' && status !== 'RED') status = 'YELLOW';
  }
}

flag(d.disk_pct !== null && d.disk_pct > 85, 'Disk at ' + d.disk_pct + '% (critical: 85%)', 'RED');
flag(d.disk_pct !== null && d.disk_pct > 70 && d.disk_pct <= 85, 'Disk at ' + d.disk_pct + '% (warn: 70%)', 'YELLOW');
flag(d.memory_pct !== null && d.memory_pct > 90, 'Memory at ' + d.memory_pct + '% (critical: 90%)', 'RED');
flag(d.memory_pct !== null && d.memory_pct > 80 && d.memory_pct <= 90, 'Memory at ' + d.memory_pct + '% (warn: 80%)', 'YELLOW');
flag(d.load_1m !== null && d.load_1m > 4, 'Load avg ' + d.load_1m + ' (critical: 4.0)', 'RED');
flag(d.load_1m !== null && d.load_1m > 2 && d.load_1m <= 4, 'Load avg ' + d.load_1m + ' (warn: 2.0)', 'YELLOW');
flag(d.n8n_status === 'down', 'n8n not responding', 'RED');
flag(d.postgres_status === 'down', 'PostgreSQL not responding', 'RED');
flag((d.skill_failures_24h || 0) > 1, String(d.skill_failures_24h) + ' skill failures in last 24h', 'RED');
flag((d.skill_failures_24h || 0) === 1, '1 skill failure in last 24h', 'YELLOW');
flag((d.lock_file_stale_minutes || 0) > 60, 'Lock file stale ' + d.lock_file_stale_minutes + 'm (stuck run?)', 'RED');
flag((d.lock_file_stale_minutes || 0) > 10 && (d.lock_file_stale_minutes || 0) <= 60, 'Lock file present ' + d.lock_file_stale_minutes + 'm', 'YELLOW');

const emoji = status === 'RED' ? '\u{1F534}' : status === 'YELLOW' ? '\u{1F7E1}' : '\u{1F7E2}';
const label = status === 'RED' ? 'CRITICAL' : status === 'YELLOW' ? 'Warning' : 'OK';
const ts = new Date().toLocaleString('en-IL', {timeZone: 'Asia/Jerusalem', hour12: false, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit'});

let msg = emoji + ' *Server ' + label + '* \u2014 ' + ts + '\n';
if (issues.length > 0) {
  msg += issues.map(function(i) { return '\u2022 ' + i; }).join('\n') + '\n';
  if (status === 'RED') msg += '_\u26a0\ufe0f Morning skills may fail._\n';
  msg += '\n';
}

const dStr = d.disk_pct !== null ? d.disk_pct + '%' : 'n/a';
const mStr = d.memory_pct !== null ? d.memory_pct + '%' : 'n/a';
const lStr = d.load_1m !== null ? String(d.load_1m) : 'n/a';
const n8nIcon = d.n8n_status === 'up' ? '\u2705' : (d.n8n_status === 'down' ? '\u274c' : '\u2753');
const pgIcon = d.postgres_status === 'up' ? '\u2705' : (d.postgres_status === 'down' ? '\u274c' : '\u2753');
const runs = d.skill_runs_24h || 0;
const fails = d.skill_failures_24h || 0;

msg += '\ud83d\udcbe Disk: ' + dStr + ' \u00b7 \ud83e\udde0 RAM: ' + mStr + ' \u00b7 \u26a1 Load: ' + lStr + '\n';
msg += '\ud83d\udc33 n8n ' + n8nIcon + ' \u00b7 skill-api \u2705 \u00b7 postgres ' + pgIcon + '\n';
msg += '\ud83d\udcca 24h: ' + runs + ' run' + (runs !== 1 ? 's' : '') + (fails > 0 ? ', ' + fails + ' failed \u274c' : ', all OK \u2705');

return [{json: {status: status, message: msg}}];
